    @Resource
    private PlayerAdditionalInformationMapper mapper;

    @Override
    public void savePlayerData(Player player) {
        if (player != null) {
            List<ApiClientResult> apiClientResults = new ArrayList<>();
            int freeNum = 0;
            int totalFreeNum = 0;
            String usedFeature = "No";
            double beforeScore = player.getUser().getScore();
            if (player.extendDataContainsKey("beforeScore")) {
                beforeScore = player.getExtendData("beforeScore",Double.class);
            }
            if (player.extendDataContainsKey("apiClient")) {
                apiClientResults = player.getExtendDataList("apiClient", ApiClientResult.class);
                usedFeature = apiClientResults.get(0).getFlow().getPurchased_feature().containsKey("name") ? "Freespin buy" : "No";
                totalFreeNum = apiClientResults.size() - 1;
            }
            if (player.extendDataContainsKey("freeNum")) {
                freeNum = player.getEFreeNum();
            }

            double stake = player.getEBetScore();
            PlayerAdditionalInformation pai = new PlayerAdditionalInformation();
            pai.setUserId(player.getUserId()).setLastUi(JSONObject.toJSONString(apiClientResults))
                            .setBetScore(stake).setFreeNum(freeNum).setTotalFreeNum(totalFreeNum)
                            .setUsedFeature(usedFeature).setBeforeScore(beforeScore)
                            .setUpdateTime(TimeUtil.getNow());
            int result = mapper.upsertLastUiByUserId(pai);
            log.info("userId = {}, saveData = {}.result = {}", player.getUser().getUserID(),JSONObject.toJSONString(pai),result);
        }
    }

    @Override
    public void restorePlayerData(Player player, JSONObject gameInfo) {
        JSONObject options = gameInfo.getJSONObject("options");
        options.put("layout", LayoutData.builder().reels(5).rows(5).build());
        options.put("paytable", JSONObject.parseObject("{\"1\":[0,0,20,40,60],\"2\":[0,0,15,25,30],\"3\":[0,0,10,20,25],\"4\":[0,0,6,12,15],\"5\":[0,0,6,10,12],\"6\":[0,0,3,5,6],\"7\":[0,0,3,5,6],\"8\":[0,0,3,4,5],\"9\":[0,0,3,4,5],\"10\":[0,0,2,3,4],\"11\":[0,0,2,3,4]}"));
        options.put("paytables",JSONObject.parseObject("{\"1\":{\"default\":[0,0,20,40,60]},\"2\":{\"default\":[0,0,15,25,30]},\"3\":{\"default\":[0,0,10,20,25]},\"4\":{\"default\":[0,0,6,12,15]},\"5\":{\"default\":[0,0,6,10,12]},\"6\":{\"default\":[0,0,3,5,6]},\"7\":{\"default\":[0,0,3,5,6]},\"8\":{\"default\":[0,0,3,4,5]},\"9\":{\"default\":[0,0,3,4,5]},\"10\":{\"default\":[0,0,2,3,4]},\"11\":{\"default\":[0,0,2,3,4]}}"));
        options.put("reels", JSONObject.parseObject(REELS));
        options.put("screen", JSONArray.parse(SCREEN));
        options.put("feature_options", ChickenRushContext.getFeatureOptions());
        options.put("special_symbols", JSONArray.parse("[{\"kind\":\"wild\",\"symbol\":\"13\"},{\"kind\":\"bonus\",\"symbol\":\"14\"}]"));
        options.put("digit_options",JSONObject.parseObject("{\"bet\":2,\"paytable\":2,\"balance\":2}"));
        options.put("base_bet",20);
        restoreData(player,gameInfo);
    }

    private void restoreData(Player player, JSONObject gameInfo) {
        if (player.extendDataContainsKey("apiClient")) {
            List<ApiClientResult> apiClient = player.getExtendDataList("apiClient", ApiClientResult.class);
            if (!apiClient.isEmpty() && apiClient.size() > 1) {
                ApiClientResult apiClientResult = apiClient.get(apiClient.size() - 1 - player.getEFreeNum());
                if (!apiClientResult.getFlow().getState().equals("closed")) {
                    apiClientResult.getOutcome().getStorage().setSticky_symbols(null);
                    gameInfo.put("outcome",JSONObject.parseObject(JSONObject.toJSONString(apiClientResult.getOutcome())));
                    JSONObject jsonObject = JSONObject.parseObject(JSONObject.toJSONString(apiClientResult.getFlow()));
                    jsonObject.put("command","init");
                    gameInfo.put("flow",jsonObject);
                    player.setExtendData("beforeScore",DecimalUtil.getBigDecimal2(player.getUser().getScore()));
                }
                if (apiClientResult.getFeatures() != null) {
                    Integer leftNum = apiClientResult.getFeatures().getInteger("freespins_left");
                    if (leftNum > 0) {
                        JSONObject features = JSONObject.parseObject(JSONObject.toJSONString(apiClientResult.getFeatures()));
                        gameInfo.put("features",features);
                    }
                }
                double totalScore = 0;
                for (int i = 0; i < apiClient.size() - 1 - player.getEFreeNum(); i++) {
                    totalScore += apiClient.get(i).getOutcome().getWin().doubleValue();
                }
                Balance balance = new Balance(DecimalUtil.getBigDecimal2(totalScore),DecimalUtil.getBigDecimal2(player.getUser().getScore() * ChickenRushContext.SUB_UNITS));
                gameInfo.put("balance",balance);

            }
        } else {
            PlayerAdditionalInformation pai = mapper.getAdditionalInformation(player.getUserId());
            if (pai != null) {
                String lastUi = pai.getLastUi();
                List<ApiClientResult> apiClientResults = JSONArray.parseArray(lastUi, ApiClientResult.class);
                player.setExtendData("apiClient",apiClientResults);
                player.setEFreeNum(pai.getFreeNum());
                player.setEBetScore(DecimalUtil.getBigDecimal2(pai.getBetScore()).doubleValue());
                player.setExtendData("beforeScore",DecimalUtil.getBigDecimal2(player.getUser().getScore()));
                if (!apiClientResults.isEmpty() && apiClientResults.size() > 1) {
                    ApiClientResult apiClientResult = apiClientResults.get(apiClientResults.size() - 1 - player.getEFreeNum());
                    if (!apiClientResult.getFlow().getState().equals("closed")) {
                        gameInfo.put("outcome",JSONObject.parseObject(JSONObject.toJSONString(apiClientResult.getOutcome())));
                        JSONObject jsonObject = JSONObject.parseObject(JSONObject.toJSONString(apiClientResult.getFlow()));
                        jsonObject.put("command","init");
                        gameInfo.put("flow",jsonObject);
                        double totalScore = 0;
                        for (int i = 0; i < apiClientResults.size() - 1 - player.getEFreeNum(); i++) {
                            totalScore += apiClientResults.get(i).getOutcome().getWin().doubleValue();
                        }
                        Balance balance = new Balance(DecimalUtil.getBigDecimal2(totalScore),DecimalUtil.getBigDecimal2(player.getUser().getScore() * ChickenRushContext.SUB_UNITS));
                        gameInfo.put("balance",balance);
                    }
                    if (apiClientResult.getFeatures() != null) {
                        Integer leftNum = apiClientResult.getFeatures().getInteger("freespins_left");
                        if (leftNum > 0) {
                            JSONObject features = JSONObject.parseObject(JSONObject.toJSONString(apiClientResult.getFeatures()));
                            gameInfo.put("features",features);
                        }
                    }
                    double realStake = player.getEBetScore();
                    if (apiClientResult.getFlow().getPurchased_feature().containsKey("level")) {
                        int level = apiClientResult.getFlow().getPurchased_feature().getInteger("level");
                        if (level == 0) {
                            realStake = DecimalUtil.getBigDecimal2(player.getEBetScore() * 50 / ChickenRushContext.SUB_UNITS).doubleValue();
                        } else if (level == 1) {
                            realStake = DecimalUtil.getBigDecimal2(player.getEBetScore() * 100 / ChickenRushContext.SUB_UNITS).doubleValue();
                        } else {
                            realStake = DecimalUtil.getBigDecimal2(player.getEBetScore() * 300 / ChickenRushContext.SUB_UNITS).doubleValue();
                        }
                    }
                    player.setExtendData("realStake",realStake);
                }
                log.info("userid = {},restoreData = {}", player.getUserId(), JSONObject.toJSONString(pai));
            } else {
                log.info("userid = {},No restoreData", player.getUserId());
            }
        }


    }

